<script setup lang="ts">import { computed,onMounted,ref,watch } from 'vue';import { useRoute } from 'vue-router';import { adminApi } from '@/api';import { ElMessage,ElMessageBox } from 'element-plus';import type { DocumentTask,KnowledgeBase } from '@/types';const route=useRoute(),knowledge=ref<KnowledgeBase[]>([]),selected=ref<number>(),list=ref<DocumentTask[]>([]),loading=ref(false),uploading=ref(false);const accept='.txt,.md,.pdf,.doc,.docx';onMounted(async()=>{knowledge.value=await adminApi.knowledge();selected.value=Number(route.query.kb)||knowledge.value[0]?.id});watch(selected,load);async function load(){if(!selected.value)return;loading.value=true;try{list.value=await adminApi.documents(selected.value)}finally{loading.value=false}}async function upload(options:any){if(!selected.value)return;uploading.value=true;try{await adminApi.upload(selected.value,options.file);ElMessage.success('文件已上传，正在异步处理');load()}catch(e){ElMessage.error((e as Error).message)}finally{uploading.value=false}}async function retry(id:number){await adminApi.retry(id);ElMessage.success('已提交重试');load()}async function remove(id:number){await ElMessageBox.confirm('将同时删除向量与物理文件，确认继续？','删除文档',{type:'warning'});await adminApi.removeDocument(id);load()}function tag(status:string){return({READY:'success',FAILED:'danger',PROCESSING:'warning',PENDING:'info',DELETING:'warning'} as any)[status]??'info'}const ready=computed(()=>list.value.filter(x=>x.status==='READY').length)</script>
<template><div class="page"><header class="page-head"><div><span class="eyebrow">DOCUMENT INGESTION</span><h1>文档管理</h1><p>上传后自动解析、切片和向量化；失败任务保留原因并支持重试。</p></div><div class="head-actions"><el-select v-model="selected" placeholder="选择知识库" style="width:220px"><el-option v-for="kb in knowledge" :key="kb.id" :label="kb.name" :value="kb.id"/></el-select><el-upload :show-file-list="false" :accept="accept" :http-request="upload"><el-button type="primary" :loading="uploading" :disabled="!selected">上传文档</el-button></el-upload></div></header><div class="inline-stats"><span>文档总数 <b>{{list.length}}</b></span><span>已就绪 <b>{{ready}}</b></span></div><el-table v-loading="loading" :data="list" class="glass-table"><el-table-column prop="originalName" label="文件名" min-width="250"/><el-table-column prop="extension" label="类型" width="90"/><el-table-column label="大小" width="120"><template #default="{row}">{{(row.fileSize/1024).toFixed(1)}} KB</template></el-table-column><el-table-column label="状态" width="120"><template #default="{row}"><el-tag :type="tag(row.status)">{{row.status}}</el-tag></template></el-table-column><el-table-column prop="chunkCount" label="切片" width="90"/><el-table-column label="失败原因" min-width="220"><template #default="{row}"><span class="error-text">{{row.failureReason||'-'}}</span></template></el-table-column><el-table-column label="操作" width="160"><template #default="{row}"><el-button v-if="row.status==='FAILED'" text type="primary" @click="retry(row.id)">重试</el-button><el-button text type="danger" :disabled="row.status==='PROCESSING'" @click="remove(row.id)">删除</el-button></template></el-table-column></el-table><el-empty v-if="selected&&!loading&&!list.length" description="暂无文档，上传一个开始构建知识库"/></div></template>
